code = """import re, json
import pandas as pd

biz = pd.DataFrame(var_call_DMnXaKt5cSpXDxV3fg5tl8Np)
rev = pd.DataFrame(var_call_Iq6ESekLutdv23BfIQyYReE1)

# extract US state abbreviation from description (e.g., ", PA,")
state_pattern = re.compile(r',\s*([A-Z]{2})[ ,]')

biz['state'] = biz['description'].apply(lambda d: state_pattern.search(d).group(1) if isinstance(d, str) and state_pattern.search(d) else None)

# count wifi businesses per state
state_counts = biz.dropna(subset=['state']).groupby('state').size().reset_index(name='wifi_business_count')

if state_counts.empty:
    result = {"state": None, "wifi_business_count": 0, "avg_rating": None}
else:
    top_state_row = state_counts.sort_values(['wifi_business_count','state'], ascending=[False, True]).iloc[0]
    top_state = top_state_row['state']

    # businesses in that state
    state_biz = biz[biz['state'] == top_state].copy()
    # map business_id -> business_ref
    state_biz['business_ref'] = state_biz['business_id'].str.replace('businessid_','businessref_', regex=False)

    # join with review averages
    merged = state_biz.merge(rev, how='left', on='business_ref')
    merged['avg_rating'] = pd.to_numeric(merged['avg_rating'], errors='coerce')
    overall_avg = merged['avg_rating'].mean()

    result = {
        "state": top_state,
        "wifi_business_count": int(top_state_row['wifi_business_count']),
        "avg_rating": None if pd.isna(overall_avg) else round(float(overall_avg), 3)
    }

out = json.dumps(result)
print("__RESULT__:")
print(out)"""

